developer.codeExample:
// Initialize Pave SDK
import { Pave } from '@pave/sdk';

const pave = new Pave({
  apiKey: process.env.PAVE_API_KEY,
  environment: 'production'
});

// Create a payment link
const payment = await pave.payments.create({
  amount: 100.00,
  currency: 'USD',
  description: 'Premium Plan',
  successUrl: 'https://yourapp.com/success',
  cancelUrl: 'https://yourapp.com/cancel'
});
